document.getElementById(`insert-selected`).addEventListener(`click`,()=>{let e=window.parent?.tinymce;if(!e){console.error(`TinyMCE not found on window.parent`);return}let t=Array.from(document.querySelectorAll(`[data-mle-media-select-checkbox]:checked`)).map(e=>({url:e.dataset.url,alt:e.dataset.alt||``,vspace:`1rem`,hspace:`1rem`,border:0,borderstyle:`none`}));if(!t.length){e.activeEditor.windowManager.alert(`Please select one image.`);return}if(t.length>1){e.activeEditor.windowManager.alert(`Please select only one image.`);return}let n=t[0];window.close(),window.parent.postMessage({mce:!0,content:n},`*`)});